fn docpartobj_default_gallery_enum_opens_clean() {
    let body = r#"<w:p><w:sdt><w:sdtPr><w:id w:val="501"/><w:docPartObj><w:docPartGallery w:val="default"/><w:docPartUnique/></w:docPartObj></w:sdtPr><w:sdtContent><w:r><w:t>x</w:t></w:r></w:sdtContent></w:sdt></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "§17.18.16 (ST_DocPartGallery): 'default' (No Gallery Classification) is a valid enum member, so the document is conformant and Word opens it without repair. issues: {detail}"
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:val="default""#),
        "§17.18.16 + §A.1 (CT_SdtDocPart): verbatim SDT preservation must keep the literal 'default' gallery token; remapping it would erase the entry's 'No Gallery Classification' semantics. expected XML to contain w:val=\"default\". got: {xml}"
    );
}

