#[test]
fn docpartunique_off_value_preserved_ct_onoff() {
    let body = r#"<w:p><w:sdt><w:sdtPr><w:id w:val="4102"/><w:docPartObj><w:docPartGallery w:val="custom1"/><w:docPartUnique w:val="0"/></w:docPartObj></w:sdtPr><w:sdtContent><w:p><w:r><w:t>block</w:t></w:r></w:p></w:sdtContent></w:sdt></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);

    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "§A.1 (CT_SdtDocPart) + ST_OnOff: docPartUnique is CT_OnOff and ST_OnOff admits '0', so the SDT is schema-valid and Word opens it without repair. issues: {detail}"
    );

    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"<w:docPartUnique w:val="0"/>"#),
        "§17.5.2.14 + ST_OnOff: the explicit off-value is a distinct on/off state; verbatim SDT preservation must keep w:val=\"0\" — collapsing to <w:docPartUnique/> would flip uniqueness to true. expected XML to contain <w:docPartUnique w:val=\"0\"/>. got: {xml}"
    );
}

